import{_ as i,o as a,c as o,ak as s}from"./chunks/framework.Dpc0wyhY.js";const u=JSON.parse('{"title":"Conversations","description":"","frontmatter":{},"headers":[],"relativePath":"grindr-api/messaging/conversations.md","filePath":"grindr-api/messaging/conversations.md"}'),n={name:"grindr-api/messaging/conversations.md"};function t(l,e,r,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="conversations" tabindex="-1">Conversations <a class="header-anchor" href="#conversations" aria-label="Permalink to “Conversations”">​</a></h1><h2 id="conversation-id" tabindex="-1">Conversation ID <a class="header-anchor" href="#conversation-id" aria-label="Permalink to “Conversation ID”">​</a></h2><p>String with two long integers separated by <code>:</code>, e.g. <code>&quot;12345678:23456789&quot;</code>. Long integers are IDs of <a href="/grindr-api/users/profiles#profile">Profile</a>. The order of these IDs is always from smaller ID to higher ID, regardless of who started the chat.</p><h2 id="conversation" tabindex="-1">Conversation <a class="header-anchor" href="#conversation" aria-label="Permalink to “Conversation”">​</a></h2><ul><li><code>type</code> — string, e.g. <code>&quot;full_conversation_v1&quot;</code></li><li><code>data</code> — nested object <ul><li><code>conversationId</code> — <a href="#conversation-id">Conversation ID</a></li><li><code>name</code> — string, profile name, may be an empty string, e.g. <code>&quot;&quot;</code></li><li><code>participants</code> — array of objects <ul><li><code>profileId</code> — integer, <a href="/grindr-api/users/profiles#profilemin">Profile ID</a></li><li><code>primaryMediaHash</code> — string or <code>null</code>, see <a href="/grindr-api/media/public-cdn-files">Media -&gt; Public CDN files</a></li><li><code>lastOnline</code> — unix timestamp in milliseconds</li><li><code>onlineUntil</code> — unix timestamp in milliseconds or <code>null</code></li><li><code>distanceMetres</code> — float number or <code>null</code></li><li><code>position</code> — <a href="/grindr-api/users/profiles#sexual-position-id">Sexual position ID</a> or <code>null</code></li><li><code>isInAList</code> — boolean</li><li><code>hasDatingPotential</code> — boolean</li></ul></li><li><code>lastActivityTimestamp</code> — unix timestamp in milliseconds</li><li><code>unreadCount</code> — integer</li><li><code>preview</code> — nested object <ul><li><code>conversationId</code> — nested object <ul><li><code>value</code> — <a href="#conversation-id">Conversation ID</a></li></ul></li><li><code>messageId</code> — string, see <a href="/grindr-api/messaging/messages#message">Message</a> for format</li><li><code>chat1MessageId</code> — string with UUIDv4, second part of <code>messageId</code></li><li><code>senderId</code> — integer, <a href="/grindr-api/users/profiles#profilemin">Profile ID</a></li><li><code>type</code> — <a href="/grindr-api/messaging/messages#message-type">Message type</a></li><li><code>chat1Type</code> — string, see <a href="/grindr-api/messaging/messages#message-type">Message type</a></li><li><code>text</code> — string or <code>null</code>, message text</li><li><code>url</code> — unknown, appears to be <code>null</code></li><li><code>lat</code> — unknown, appears to be <code>null</code></li><li><code>lon</code> — unknown, appears to be <code>null</code></li><li><code>albumId</code> — integer, appears to be <code>null</code></li><li><code>albumContentId</code> — unknown, appears to be <code>null</code></li><li><code>albumContentReply</code> — unknown, appears to be <code>null</code></li><li><code>duration</code> — unknown, appears to be <code>null</code></li><li><code>imageHash</code> — unknown, appears to be <code>null</code></li><li><code>photoContentReply</code> — unknown, appears to be <code>null</code></li></ul></li><li><code>muted</code> — boolean</li><li><code>pinned</code> — boolean</li><li><code>favorite</code> — boolean</li><li><code>context</code> — unknown, appears to be <code>null</code></li><li><code>onlineUntil</code> — unknown, appears to be <code>null</code></li><li><code>translatable</code> — boolean</li><li><code>rightNow</code> — string, e.g. <code>&quot;NOT_ACTIVE&quot;</code></li><li><code>hasUnreadThrob</code> — boolean</li></ul></li></ul><h2 id="get-conversations" tabindex="-1">Get conversations <a class="header-anchor" href="#get-conversations" aria-label="Permalink to “Get conversations”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/inbox</span></span></code></pre></div><p><em>Also <code>POST /v3/inbox</code>, seems to be aliased to v4 now</em></p><p>Query (optional):</p><ul><li><code>page</code> — 1-based number, pagination</li></ul><p>Body (optional):</p><ul><li><code>unreadOnly</code> — boolean</li><li><code>chemistryOnly</code> — boolean</li><li><code>favoritesOnly</code> — boolean</li><li><code>rightNowOnly</code> — boolean</li><li><code>onlineNowOnly</code> — boolean</li><li><code>distanceMeters</code> — &quot;double&quot; number value or <code>null</code></li><li><code>positions</code> — array of integers, <a href="/grindr-api/users/profiles#sexual-position-id">sexual position IDs</a></li></ul><p>Response:</p><ul><li><code>entries</code> — array of <a href="#conversation">Conversation</a></li><li><code>showsFreeHeaderLabel</code> — boolean</li><li><code>totalFullConversations</code> — number, e.g. <code>&quot;5&quot;</code></li><li><code>totalPartialConversations</code> — number, e.g. <code>0</code></li><li><code>maxDisplayLockCount</code> — number, e.g. <code>99</code></li><li><code>nextPage</code> — integer, e.g. <code>2</code></li></ul><h2 id="get-conversations-by-ids" tabindex="-1">Get conversations by IDs <a class="header-anchor" href="#get-conversations-by-ids" aria-label="Permalink to “Get conversations by IDs”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v1/inbox/conversation</span></span></code></pre></div><p>Body:</p><ul><li>Array of <a href="#conversation-id">Conversation IDs</a></li></ul><p>Response (array):</p><ul><li><code>conversationId</code> - string, e.g. <code>647135273:771038429</code></li><li><code>name</code> - string, profile name, may be an empty string, e.g. <code>&quot;&quot;</code></li><li><code>participants</code> - array of objects <ul><li><code>profileId</code> - integer, <a href="/grindr-api/users/profiles#profilemin">Profile ID</a></li><li><code>primaryMediaHash</code> - string or <code>null</code>, see <a href="/grindr-api/media/public-cdn-files#profile-images">Media -&gt; Public CDN files -&gt; Profile Images</a></li><li><code>lastOnline</code> - unix timestamp in milliseconds</li><li><code>distanceMetres</code> - float number or <code>null</code></li><li><code>lastActivityTimestamp</code> - unix timestamp in milliseconds</li><li><code>unreadCount</code> - integer</li><li><code>preview</code> - nested object <ul><li><code>conversationId</code> - nested object <ul><li><code>value</code> - <a href="#conversation-id">Conversation ID</a></li></ul></li><li><code>messageId</code> - string, see <a href="/grindr-api/messaging/messages#message">Message</a> for format</li><li><code>chat1MessageId</code> - string with UUIDv4, second part of <code>messageId</code></li><li><code>senderId</code> - integer, <a href="/grindr-api/users/profiles#profilemin">Profile ID</a></li><li><code>type</code> - <a href="/grindr-api/messaging/messages#message-type">Message type</a></li><li><code>chat1Type</code> - string, see <a href="/grindr-api/messaging/messages#message-type">Message type</a></li><li><code>text</code> - string or <code>null</code>, message text</li><li><code>url</code> - unknown, appears to be <code>null</code></li><li><code>lat</code> - unknown, appears to be <code>null</code></li><li><code>lon</code> - unknown, appears to be <code>null</code></li><li><code>albumId</code> - integer, appears to be <code>null</code></li><li><code>albumContentId</code> - unknown, appears to be <code>null</code></li><li><code>albumContentReply</code> - unknown, appears to be <code>null</code></li><li><code>duration</code> - unknown, appears to be <code>null</code></li><li><code>imageHash</code> - unknown, appears to be <code>null</code></li><li><code>photoContentReply</code> - unknown, appears to be <code>null</code></li></ul></li><li><code>muted</code> - boolean</li><li><code>pinned</code> - boolean</li><li><code>favorite</code> - boolean</li><li><code>context</code> - unknown, appears to be <code>null</code></li><li><code>onlineUntil</code> - unknown, appears to be <code>null</code></li><li><code>translatable</code> - boolean</li><li><code>rightNow</code> - string, e.g. <code>&quot;NOT_ACTIVE&quot;</code></li><li><code>hasUnreadThrob</code> - boolean</li></ul></li></ul><h2 id="delete-a-conversation" tabindex="-1">Delete a conversation <a class="header-anchor" href="#delete-a-conversation" aria-label="Permalink to “Delete a conversation”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Deletes the conversation on your side. Does not delete the conversation for other chat&#39;s participant.</p><p>Repeated requests are completed without errors.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>DELETE /v4/chat/conversation/{conversationId}</span></span></code></pre></div><p>Response:</p><p>Empty.</p><h2 id="pin-a-conversation" tabindex="-1">Pin a conversation <a class="header-anchor" href="#pin-a-conversation" aria-label="Permalink to “Pin a conversation”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Affects sorting position in <a href="#list-conversations">list conversations</a> endpoint response.</p><p>Repeated requests are completed without errors. Requests on nonexistent conversations seem to be affecting them after they have been created.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/chat/conversation/{conversationId}/pin</span></span></code></pre></div><p>No body.</p><p>Response:</p><p>Empty.</p><h2 id="unpin-a-conversation" tabindex="-1">Unpin a conversation <a class="header-anchor" href="#unpin-a-conversation" aria-label="Permalink to “Unpin a conversation”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Affects sorting position in <a href="#list-conversations">list conversations</a> endpoint response. Requests on nonexistent conversations seem to be affecting them after they have been created.</p><p>Repeated requests are completed without errors.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/chat/conversation/{conversationId}/unpin</span></span></code></pre></div><p>No body.</p><p>Response:</p><p>Empty.</p><h2 id="mute-a-conversation" tabindex="-1">Mute a conversation <a class="header-anchor" href="#mute-a-conversation" aria-label="Permalink to “Mute a conversation”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Requests on nonexistent conversations seem to be affecting them after they have been created.</p><p>Repeated requests are completed without errors.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v1/push/conversation/{conversationId}/mute</span></span></code></pre></div><p>No body.</p><p>Response:</p><p>Empty</p><h2 id="unmute-a-conversation" tabindex="-1">Unmute a conversation <a class="header-anchor" href="#unmute-a-conversation" aria-label="Permalink to “Unmute a conversation”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Requests on nonexistent conversations seem to be affecting them after they have been created.</p><p>Repeated requests are completed without errors.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v1/push/conversation/{conversationId}/unmute</span></span></code></pre></div><p>No body.</p><p>Response:</p><p>Empty</p><h2 id="get-shared-media-in-conversation" tabindex="-1">Get shared media in conversation <a class="header-anchor" href="#get-shared-media-in-conversation" aria-label="Permalink to “Get shared media in conversation”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v5/chat/media/shared/images/with-me/{conversationId}</span></span></code></pre></div><p>Response:</p><ul><li><code>images</code> - array of <a href="/grindr-api/messaging/messages#chatimage">ChatImage</a></li></ul><h2 id="refresh-messages" tabindex="-1">Refresh messages <a class="header-anchor" href="#refresh-messages" aria-label="Permalink to “Refresh messages”">​</a></h2><p>Requests the messages from the message id</p><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/chat/conversation/{conversationId}/message-by-id</span></span></code></pre></div><p>Body:</p><ul><li><code>messageIds</code> — array of strings</li></ul><p>Response:</p><ul><li><code>messages</code> — array of <a href="/grindr-api/messaging/messages#message">Message</a></li></ul><h2 id="mark-messages-as-read" tabindex="-1">Mark messages as read <a class="header-anchor" href="#mark-messages-as-read" aria-label="Permalink to “Mark messages as read”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/chat/conversation/{conversationId}/read/{messageId}</span></span></code></pre></div><p>Regardless of messageId passed, the whole conversation&#39;s <a href="#conversation"><code>unreadCount</code></a> will be reset to 0. messageId is taken into account to present the &quot;Read&quot; label to sender.</p><p>If you&#39;d like to mark conversation as read but don&#39;t show it to other participant, you could pass a valid but nonexistent messageId, such as <code>0:00000000-0000-0000-0000-000000000000</code>.</p><p>Invalid messageIds will cause HTTP status 400 Bad Request errors.</p><p>No body.</p><p>Response:</p><p>Empty.</p><h2 id="ai-chat-suggestions" tabindex="-1">AI chat suggestions <a class="header-anchor" href="#ai-chat-suggestions" aria-label="Permalink to “AI chat suggestions”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v1/chat/suggestions</span></span></code></pre></div><p>Query:</p><ul><li><code>conversationId</code> — string</li></ul><p>Response:</p><ul><li><code>suggestions</code> — array of objects <ul><li><code>id</code> — UUIDv3</li><li><code>text</code> — string</li><li><code>type</code> — <code>SAVED_PHRASE</code> | <code>SMART_PHRASE</code></li></ul></li></ul><h2 id="chat-ai-summary-feedback-wip" tabindex="-1">Chat AI summary feedback, WIP <a class="header-anchor" href="#chat-ai-summary-feedback-wip" aria-label="Permalink to “Chat AI summary feedback, WIP”">​</a></h2><p>POST /v1/chat/summary/feedback WingmanSummaryFeedbackDto</p>',91)])])}const g=i(n,[["render",t]]);export{u as __pageData,g as default};
